            _ = params
        
            retRes14128 := (<-this.LoadMarkets())
            ccxt.PanicOnError(retRes14128)
            // symbols are required
            symbols = this.MarketSymbols(symbols, nil, false, true, false)
            var messageHashes any = []any{}
